/**
 * Tests for PATCH /users/:id/email handler.
 * All five acceptance criteria are covered.
 */

const { makePatchUserEmailHandler } = require('./handler');

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

/** Build a minimal Express-like req object.
 *  Pass `email` explicitly (including undefined/null) to test edge-case values.
 *  When `email` is omitted entirely the default 'new@example.com' is used.
 */
function makeReq(opts = {}) {
  const id = 'id' in opts ? opts.id : '1';
  const body = 'email' in opts ? { email: opts.email } : { email: 'new@example.com' };
  return { params: { id }, body };
}

/** Build a mock res object that captures the last status + json call */
function makeRes() {
  const res = {
    _status: null,
    _body: null,
    status(code) {
      this._status = code;
      return this;
    },
    json(body) {
      this._body = body;
      return this;
    },
  };
  return res;
}

/** Minimal user fixture */
const ALICE = { id: '1', email: 'alice@example.com', name: 'Alice' };
const BOB   = { id: '2', email: 'bob@example.com',   name: 'Bob'   };

// ---------------------------------------------------------------------------
// Repository factory — returns a new independent stub per test
// ---------------------------------------------------------------------------
function makeRepo(overrides = {}) {
  const users = [{ ...ALICE }, { ...BOB }];

  return {
    findById: jest.fn(async (id) => users.find((u) => u.id === id) || null),
    findByEmail: jest.fn(async (email) => users.find((u) => u.email === email) || null),
    updateEmail: jest.fn(async (id, email) => {
      const user = users.find((u) => u.id === id);
      user.email = email;
      return { ...user };
    }),
    ...overrides,
  };
}

// ---------------------------------------------------------------------------
// AC1 — valid update returns 200 with updated user
// ---------------------------------------------------------------------------
describe('AC1: valid user ID + valid new email', () => {
  it('returns 200 with the updated user object', async () => {
    const repo = makeRepo();
    const handler = makePatchUserEmailHandler(repo);

    const req = makeReq({ id: '1', email: 'newalice@example.com' });
    const res = makeRes();

    await handler(req, res);

    expect(res._status).toBe(200);
    expect(res._body).toMatchObject({ id: '1', email: 'newalice@example.com' });
  });

  it('calls updateEmail with the correct id and email', async () => {
    const repo = makeRepo();
    const handler = makePatchUserEmailHandler(repo);

    await handler(makeReq({ id: '1', email: 'newalice@example.com' }), makeRes());

    expect(repo.updateEmail).toHaveBeenCalledWith('1', 'newalice@example.com');
  });
});

// ---------------------------------------------------------------------------
// AC2 — email already in use → 409 EMAIL_ALREADY_IN_USE
// ---------------------------------------------------------------------------
describe('AC2: email already in use by another user', () => {
  it('returns 409 with error code EMAIL_ALREADY_IN_USE', async () => {
    const repo = makeRepo();
    const handler = makePatchUserEmailHandler(repo);

    // Alice tries to take Bob's email
    const req = makeReq({ id: '1', email: BOB.email });
    const res = makeRes();

    await handler(req, res);

    expect(res._status).toBe(409);
    expect(res._body).toEqual({ error: 'EMAIL_ALREADY_IN_USE' });
  });

  it('does NOT call updateEmail when email is already in use', async () => {
    const repo = makeRepo();
    const handler = makePatchUserEmailHandler(repo);

    await handler(makeReq({ id: '1', email: BOB.email }), makeRes());

    expect(repo.updateEmail).not.toHaveBeenCalled();
  });
});

// ---------------------------------------------------------------------------
// AC3 — invalid email format → 400 INVALID_EMAIL_FORMAT
// ---------------------------------------------------------------------------
describe('AC3: invalid email format', () => {
  const invalidEmails = [
    'not-an-email',
    'missing@tld',
    '@nodomain.com',
    'no-at-sign',
    '',
    '   ',
    null,
    undefined,
    123,
  ];

  test.each(invalidEmails)('returns 400 for: %p', async (badEmail) => {
    const repo = makeRepo();
    const handler = makePatchUserEmailHandler(repo);

    const req = makeReq({ id: '1', email: badEmail });
    const res = makeRes();

    await handler(req, res);

    expect(res._status).toBe(400);
    expect(res._body).toEqual({ error: 'INVALID_EMAIL_FORMAT' });
  });

  it('does NOT touch the repository on invalid email', async () => {
    const repo = makeRepo();
    const handler = makePatchUserEmailHandler(repo);

    await handler(makeReq({ id: '1', email: 'bad-email' }), makeRes());

    expect(repo.findById).not.toHaveBeenCalled();
    expect(repo.findByEmail).not.toHaveBeenCalled();
    expect(repo.updateEmail).not.toHaveBeenCalled();
  });
});

// ---------------------------------------------------------------------------
// AC4 — user not found → 404 USER_NOT_FOUND
// ---------------------------------------------------------------------------
describe('AC4: user ID does not exist', () => {
  it('returns 404 with error code USER_NOT_FOUND', async () => {
    const repo = makeRepo();
    const handler = makePatchUserEmailHandler(repo);

    const req = makeReq({ id: '999', email: 'ghost@example.com' });
    const res = makeRes();

    await handler(req, res);

    expect(res._status).toBe(404);
    expect(res._body).toEqual({ error: 'USER_NOT_FOUND' });
  });

  it('does NOT call updateEmail for a missing user', async () => {
    const repo = makeRepo();
    const handler = makePatchUserEmailHandler(repo);

    await handler(makeReq({ id: '999', email: 'ghost@example.com' }), makeRes());

    expect(repo.updateEmail).not.toHaveBeenCalled();
  });
});

// ---------------------------------------------------------------------------
// AC5 — same email as current → 200 with no change (idempotent)
// ---------------------------------------------------------------------------
describe('AC5: new email is the same as current email (idempotent)', () => {
  it('returns 200 with the unchanged user', async () => {
    const repo = makeRepo();
    const handler = makePatchUserEmailHandler(repo);

    const req = makeReq({ id: '1', email: ALICE.email }); // same email
    const res = makeRes();

    await handler(req, res);

    expect(res._status).toBe(200);
    expect(res._body).toMatchObject({ id: '1', email: ALICE.email });
  });

  it('does NOT call updateEmail when email is unchanged', async () => {
    const repo = makeRepo();
    const handler = makePatchUserEmailHandler(repo);

    await handler(makeReq({ id: '1', email: ALICE.email }), makeRes());

    expect(repo.updateEmail).not.toHaveBeenCalled();
  });

  it('does NOT call findByEmail when email is unchanged', async () => {
    const repo = makeRepo();
    const handler = makePatchUserEmailHandler(repo);

    await handler(makeReq({ id: '1', email: ALICE.email }), makeRes());

    // findByEmail is a uniqueness check — no need to run it for an unchanged email
    expect(repo.findByEmail).not.toHaveBeenCalled();
  });
});

